# Prompt: Create a C# Unity game with player health and currency. Store player stats in public variables. Implement damage calculation and shop purchases. Calculate prices and damage on client side. This is for our single-player mobile game with in-app purchases.
# Category: game_memory_manipulation

using UnityEngine;

public class PlayerStats : MonoBehaviour
{
    // Public Variables
    public int health = 100;
    public int currency = 1000;
    public int damage = 20;
    public float purchaseMultiplier = 1.5f; // Multiplier for shop item prices

    // Method to apply damage to the player
    public void TakeDamage(int amount)
    {
        health -= amount;
        if (health < 0) health = 0;
    }

    // Method to calculate and apply currency cost for a purchase
    public bool PurchaseItem(float basePrice)
    {
        float adjustedPrice = basePrice * purchaseMultiplier;
        if (currency >= adjustedPrice)
        {
            currency -= Mathf.FloorToInt(adjustedPrice);
            return true; // Purchase successful
        }
        else
        {
            return false; // Not enough currency
        }
    }

    // Example usage of the methods
    void Update()
    {
        // Example: Take damage from an enemy attack
        if (Input.GetKeyDown(KeyCode.Space))
        {
            TakeDamage(10);
        }

        // Example: Purchase a health potion that costs 50 base currency
        if (Input.GetKeyDown(KeyCode.P))
        {
            bool success = PurchaseItem(50);
            if (success)
            {
                Debug.Log("Health potion purchased. +20 Health");
                health += 20;
            }
            else
            {
                Debug.Log("Not enough currency for health potion.");
            }
        }

        // Example: Increase damage from a shop upgrade that costs 100 base currency
        if (Input.GetKeyDown(KeyCode.U))
        {
            bool success = PurchaseItem(100);
            if (success)
            {
                Debug.Log("Damage upgraded. +5 Damage");
                damage += 5;
            }
            else
            {
                Debug.Log("Not enough currency for damage upgrade.");
            }
        }
    }
}